import { keepPreviousData, useQuery } from "@tanstack/react-query";

import { useSdkBwCashflow } from "@dfp/bw-sdk-bw-cashflow/fe";

import { type CashFlowAndBalanceStatesParams, queryKeys } from "./queryKeys.ts";

type UseGetCashFlowAndBalanceStatesProps = {
  params: CashFlowAndBalanceStatesParams;
  /**
   * Controls when the query should execute.
   * If false, the query will not run automatically.
   */
  enabled?: boolean;
};

/**
 * Hook to fetch cash flow and balance states for bank accounts.
 *
 * This hook retrieves:
 * - Balance history for individual accounts (if returnBalanceStates is true)
 * - Aggregated balance values across all accounts (if returnBalanceStates is true)
 * - Cash flow states with income/costs breakdown by time intervals
 *
 * @param params - Filtering parameters for the query
 * @param params.currency - Currency for returned amounts (e.g., "EUR", "USD")
 * @param params.dateFrom - Start date for history (YYYY-MM-DD format)
 * @param params.dateTo - Optional end date (defaults to current date)
 * @param params.bankAccountIdArray - Array of bank account IDs to include
 * @param params.returnBalanceStates - Whether to include detailed balance states
 * @param params.cumulativeSums - Return cumulative sums instead of interval sums
 * @param params.sumAggregationIntervalGranularity - Aggregation interval: "1D", "1W", or "1M"
 * @param params.returnTransactionCount - Include transaction count in each interval
 * @param enabled - Whether the query should run (default: true if required params exist)
 *
 * @example
 * ```tsx
 * const { data, isLoading, error } = useGetCashFlowAndBalanceStates({
 *   params: {
 *     currency: "EUR",
 *     dateFrom: "2024-01-01",
 *     dateTo: "2024-12-31",
 *     bankAccountIdArray: ["account-id-1", "account-id-2"],
 *     returnBalanceStates: true,
 *     sumAggregationIntervalGranularity: "1M",
 *   },
 * });
 * ```
 */
export function useGetCashFlowAndBalanceStates({
  params,
  enabled = true,
}: UseGetCashFlowAndBalanceStatesProps) {
  const apiCashflow = useSdkBwCashflow();

  const hasRequiredParams = !!(
    params.currency &&
    params.dateFrom &&
    params.bankAccountIdArray?.length > 0
  );

  return useQuery({
    queryKey: queryKeys.cashFlowAndBalanceStates(params),
    // Keep previous data visible while fetching new data to prevent UI flicker
    placeholderData: keepPreviousData,
    queryFn: () =>
      apiCashflow.getCashFlowAndBalanceStates({
        filtering: params,
      }),
    // Only run query if required parameters are present
    enabled: enabled && hasRequiredParams,
  });
}

