type CashflowTabProps = {
  companyId: string;
};

export function CashflowTab({ companyId }: CashflowTabProps) {
  const { tt } = useTT();
  const { companySettings } = useCockpit();
  const clientSettings = useGetClientSettings({
    companyId,
    options: { select: getClientSettings },
  });
  const currency =
    companySettings?.currency ?? clientSettings.data?.currency ?? "EUR";
  const bankAccountIdArray = clientSettings.data?.bankAccountIdArray ?? [];

  const { tableContainerRef, columnCount } = useCashflowLayoutConfig();

  const { dateFrom, dateTo, interval, setInterval, ...timePeriodControls } =
    useCashflowTimePeriodFilter({
      columnCount,
      maxDateRangeFrom: clientSettings.data?.maxDateRangeFrom,
      // WARN: Do not remove: CAS-839
      // maxDateRangeTo: clientSettings.data?.maxDateRangeTo,
      maxDateRangeTo: dayjs().format("YYYY-MM-DD"),
      companyId,
    });

  const categoryFilterState = useCategoryFilter();
  const { categoryFilter, allCategoryValues } = categoryFilterState;

  const {
    data,
    isPending: isCashflowPending,
    isFetching,
    isPlaceholderData: isCashflowPlaceholder,
    error,
  } = useGetCashFlowAndBalanceStates({
    params: {
      dateFrom,
      dateTo,
      currency,
      bankAccountIdArray,
      sumAggregationIntervalGranularity: interval,
      category: mapCategoryFilterToParam(categoryFilter, allCategoryValues),
    },
  });

  // Cached data for the active key should render immediately. Only show loading
  // states when the active key has no cached payload yet and React Query is still
  // serving placeholder data from the previous selection.
  const isInitialLoading = clientSettings.isPending || isCashflowPending;
  const isFilterTransitionLoading =
    !isInitialLoading && isCashflowPlaceholder && isFetching;
  const isTableLoading = isInitialLoading || isFilterTransitionLoading;

  const selectedColumn = useMemo(
    () =>
      data?.cashFlowStates?.sumArray
        ? findColumnIndexForDate(
            data.cashFlowStates.sumArray,
            timePeriodControls.selectedDay,
          )
        : null,
    [data?.cashFlowStates?.sumArray, timePeriodControls.selectedDay],
  );

  if (error) {
    return (
      <EmptyState
        title={tt("error.title")}
        subtitle={error.message || tt("error.generic")}
        icon={<IconAlertCircle />}
      />
    );
  }

  if (
    !(isInitialLoading || isFilterTransitionLoading) &&
    (!data || (data.cashFlowStates?.sumArray?.length ?? 0) === 0)
  ) {
    return (
      <EmptyState
        icon={<IconBarChart03 />}
        title={tt("chart.noData")}
        subtitle={tt("chart.noDataDescription")}
      />
    );
  }

  return (
    <Stack sx={{ gap: 2 }}>
      <SelectionProvider selectedColumn={selectedColumn}>
        <TimePeriodProvider timePeriodControls={timePeriodControls}>
          {/* Upper Section - Health Indicators + Chart */}
          <Box
            sx={{
              display: "grid",
              gridTemplateColumns: {
                xs: "1fr",
                md: `${cashflowLayoutConfig.labelColumnWidth - cashflowLayoutConfig.yAxisWidth}px 1fr`,
              },
            }}
          >
            <HealthIndicatorsSection />
            <CashflowChartProvider
              data={data}
              interval={interval}
              setInterval={setInterval}
              currency={currency}
              bankAccountCount={bankAccountIdArray.length}
            >
              <CurrentBalanceChartSection
                isInitialLoading={isInitialLoading}
                isRefetching={isFilterTransitionLoading}
              />
            </CashflowChartProvider>
          </Box>

          {/* Bottom Section - Table */}
          <Box ref={tableContainerRef}>
            <CashflowTableProvider
              data={data}
              interval={interval}
              currency={currency}
              bankAccountIdArray={bankAccountIdArray}
              categoryFilterState={categoryFilterState}
            >
              <CashflowTableSection isLoading={isTableLoading} />
            </CashflowTableProvider>
          </Box>
        </TimePeriodProvider>
      </SelectionProvider>
    </Stack>
  );
}

import type {
  CashFlowResponse,
  CashflowPeriod,
  CashflowTableData,
  CategoryType,
} from "../types/cashflow-table.types.ts";

/**
 * Transforms the API response from getCashFlowAndBalanceStates into table-ready data structure.
 *
 * Key transformations:
 * - Converts category arrays to Maps for efficient lookup
 * - Extracts all unique categories present in the data
 * - Renders all periods returned by the API (no padding or truncation)
 *
 * @param apiResponse - Response from getCashFlowAndBalanceStates API
 */
export function transformCashflowData(
  apiResponse: CashFlowResponse,
): CashflowTableData {
  const { cashFlowStates } = apiResponse;
  const sumArray = cashFlowStates?.sumArray ?? [];
  const { sumAggregationalGranularity } = cashFlowStates ?? {};

  // Transform API periods to table periods
  const periods: CashflowPeriod[] = sumArray.map((period, index: number) => {
    // Convert category arrays to Maps
    const incomeCategories = new Map<CategoryType, number>();
    period.incomeCategorySum?.forEach((cat) => {
      incomeCategories.set(cat.category as CategoryType, cat.amount);
    });

    const costsCategories = new Map<CategoryType, number>();
    period.costsCategorySum?.forEach((cat) => {
      costsCategories.set(cat.category as CategoryType, cat.amount);
    });

    // Calculate balances
    const startingBalance = period.startedBalance?.balance ?? 0;
    const netBalance = period.netChange;
    const finalBalance = period.finalBalance?.balance ?? 0;

    return {
      id: `period-${index}-${period.dateFrom}`,
      dateFrom: period.dateFrom,
      dateTo: period.dateTo,
      startingBalance,
      income: period.income,
      costs: period.costs,
      netBalance,
      finalBalance,
      incomeCategories,
      costsCategories,
      transactionCount: period.transactionCount,
      // Progress percentage would be calculated here if API provides planned amounts
      progressPercentage: undefined,
    };
  });

  // Extract all unique categories that have data
  const allIncomeCategories = new Set<CategoryType>();
  const allCostsCategories = new Set<CategoryType>();

  periods.forEach((period) => {
    period.incomeCategories.forEach((_, category) => {
      allIncomeCategories.add(category);
    });
    period.costsCategories.forEach((_, category) => {
      allCostsCategories.add(category);
    });
  });

  return {
    periods,
    granularity: sumAggregationalGranularity || "1M",
    categories: {
      income: Array.from(allIncomeCategories),
      costs: Array.from(allCostsCategories),
    },
  };
}

import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";

export type CashFlowResponse =
  BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
type CashFlowStates = NonNullable<CashFlowResponse["cashFlowStates"]>;
type SumArray = NonNullable<CashFlowStates["sumArray"]>;
type SumArrayItem = SumArray[number];
type IncomeCategorySum = NonNullable<SumArrayItem["incomeCategorySum"]>;
type ApiCategoryType = IncomeCategorySum[number]["category"];

export type CategoryType = ApiCategoryType;

/**
 * Represents a single period column in the cashflow table
 */
export type CashflowPeriod = {
  id: string;
  /** Date of the period (YYYY-MM-DD) */
  dateFrom: string;
  dateTo: string;
  /** Balance at the start of this period */
  startingBalance: number;
  /** Total income for this period */
  income: number;
  /** Total costs for this period */
  costs: number;
  /** Net change (income - costs) */
  netBalance: number;
  /** Final balance at end of period (startingBalance + netBalance) */
  finalBalance: number;
  incomeCategories: Map<CategoryType, number>;
  costsCategories: Map<CategoryType, number>;
  progressPercentage?: number;
  transactionCount?: number;
};

/**
 * Complete data structure for the cashflow table
 */
export type CashflowTableData = {
  periods: CashflowPeriod[];
  granularity: "1D" | "1W" | "1M";
  categories: {
    income: CategoryType[];
    costs: CategoryType[];
  };
};

export type CategoryFilter = {
  income: CategoryType[];
