const QUALITY_TRANSLATION_KEY = {
  CALCULATED: "chart.calculated",
  IMPORTED: "chart.imported",
  DERIVED: "chart.derived",
} as const;

const ICON_SIZE = 20;

type Props = {
  balanceQuality: BalanceQuality | null | undefined;
};

export function CashflowQualityIndicator({ balanceQuality }: Props) {
  const { tt } = useTT();
  const theme = useTheme();

  if (balanceQuality !== "DERIVED" && balanceQuality !== "CALCULATED") {
    return null;
  }

  const qualityColor = getQualityThemeColor(theme, balanceQuality);
  const chipSx = {
    width: 30,
    height: 30,
    borderColor: qualityColor,
    backgroundColor: alpha(qualityColor, 0.1),
    color: qualityColor,
    "& .MuiChip-icon": { color: qualityColor },
  };

  const icon =
    balanceQuality === "DERIVED" ? (
      <IconAlertTriangle width={ICON_SIZE} height={ICON_SIZE} />
    ) : (
      <IconAlertSquare width={ICON_SIZE} height={ICON_SIZE} />
    );

  return (
    <Tooltip title={tt(QUALITY_TRANSLATION_KEY[balanceQuality])}>
      <Chip sx={chipSx} variant="outlined" icon={icon} />
    </Tooltip>
  );
}

import type { Theme } from "@mui/material";

import type { BalanceQuality } from "../types/cashflow.types.ts";

/**
 * Resolves a quality-based color from the MUI theme (for libraries that need a
 * concrete hex value, e.g. Recharts).
 */
export function getQualityThemeColor(
  theme: Theme,
  quality: BalanceQuality,
): string {
  const map: Record<BalanceQuality, string> = {
    CALCULATED: theme.palette.custom.fill,
    IMPORTED: theme.palette.custom.fill,
    DERIVED: theme.palette.custom.fillWarning,
  };
  return map[quality];
}

