/**
 * Transform API cash flow data to bar chart data format
 * @param cashFlowData - Raw cash flow intervals from API
 * @param interval - Interval granularity for labels (1D, 1W, 1M)
 * @returns Array of bar chart data points
 */
export function transformToBarChartData(
  cashFlowData: NonNullable<CashFlowInterval>[],
  interval: Interval,
): BarChartDataPoint[] {
  return cashFlowData.map((cashFlowInterval) => {
    const periodKey = createPeriodKey(
      cashFlowInterval.dateFrom,
      cashFlowInterval.dateTo,
    );
    const periodLabel = formatPeriodLabel({
      dateFrom: cashFlowInterval.dateFrom,
      dateTo: cashFlowInterval.dateTo,
      interval,
    });

    return {
      period: periodLabel,
      periodKey,
      dateFrom: cashFlowInterval.dateFrom,
      dateTo: cashFlowInterval.dateTo,
      // Display costs as positive values for better visualization
      income: cashFlowInterval.income,
      costs: Math.abs(cashFlowInterval.costs),
      netChange: cashFlowInterval.netChange,
      // Category data for future stacking feature
      incomeCategories: cashFlowInterval.incomeCategorySum,
      costsCategories: cashFlowInterval.costsCategorySum,
      // Transaction count for debugging/analytics
      transactionCount: cashFlowInterval.transactionCount,
    };
  });
}

/**
 * Transform API balance data to line chart data format
 * @param balanceData - Map of date to balance point from API
 * @param cashFlowData - Cash flow intervals for period key mapping
 * @returns Sorted array of line chart data points
 */
export function transformToLineChartData(
  balanceData: Record<string, BalancePoint>,
  cashFlowData: CashFlowInterval[],
): LineChartDataPoint[] {
  // Convert balance map to array, filter out entries without dates, and sort by date
  const balanceArray = Object.entries(balanceData)
    .map(([_, balancePoint]) => balancePoint)
    .filter((balancePoint): balancePoint is BalancePoint & { date: string } =>
      Boolean(balancePoint.date),
    )
    .sort((a, b) => dayjs(a.date).valueOf() - dayjs(b.date).valueOf());

  // Create a lookup map for finding period keys
  const periodLookup = new Map<string, string>();
  cashFlowData.forEach((interval) => {
    const periodKey = createPeriodKey(interval.dateFrom, interval.dateTo);
    const startDate = dayjs(interval.dateFrom);
    const endDate = dayjs(interval.dateTo);

    // Map all dates within this interval to the period key
    let currentDate = startDate;
    while (
      currentDate.isBefore(endDate) ||
      currentDate.isSame(endDate, "day")
    ) {
      const dateStr = formatDateToISO(currentDate);
      periodLookup.set(dateStr, periodKey);
      currentDate = currentDate.add(1, "day");
    }
  });

  // Transform to line chart format
  return balanceArray.map((balancePoint) => {
    const dateLabel = formatDateLabel(balancePoint.date);
    const periodKey = periodLookup.get(balancePoint.date) || "";
    const timestamp = dayjs(balancePoint.date).valueOf();

    return {
      date: balancePoint.date,
      timestamp,
      dateLabel,
      balance: balancePoint.balance,
      periodKey,
      balanceQuality: balancePoint.balanceQuality ?? "CALCULATED",
    };
  });
}

import { type ReactNode, useMemo, useState } from "react";

import type {
  BalancePoint,
  CashFlowInterval,
  CashflowChartContextType,
  ChartViewMode,
  Interval,
  LegendData,
} from "../../types/cashflow.types.ts";
import {
  transformToBarChartData,
  transformToLineChartData,
} from "../../utils/index.ts";
import { segmentLineChartQuality } from "../line-chart/index.ts";
import {
  CashflowChartContext,
  useCashflowChartContext,
} from "./cashflowChart.context.ts";

type CashflowChartProviderProps = {
  children: ReactNode;
  data?: {
    cashFlowStates?: {
      sumArray?: CashFlowInterval[];
    };
    aggregatedBalanceValues?: Record<string, BalancePoint> | BalancePoint[];
  };
  // Interval state from parent (where the query is made)
  interval: Interval;
  setInterval: (interval: Interval) => void;
  /** Currency code for display (e.g., "EUR", "CZK") */
  currency: string;
  /** Number of bank accounts included in the query */
  bankAccountCount: number;
};

/**
 * Provider component for cashflow chart context
 * Manages view state, selection, and data transformations
 */
export function CashflowChartProvider({
  children,
  data,
  interval,
  setInterval,
  currency,
  bankAccountCount,
}: CashflowChartProviderProps) {
  const [viewMode, setViewMode] = useState<ChartViewMode>("bar");

  const cashFlowData = useMemo(
    () => data?.cashFlowStates?.sumArray || [],
    [data],
  );

  const balanceData = useMemo(() => {
    const rawBalanceData = data?.aggregatedBalanceValues;

    if (!rawBalanceData) {
      return {};
    }

    if (!Array.isArray(rawBalanceData)) {
      return rawBalanceData;
    }

    return rawBalanceData.reduce(
      (acc, balancePoint) => {
        if (balancePoint.date) {
          acc[balancePoint.date] = balancePoint;
        }
        return acc;
      },
      {} as Record<string, BalancePoint>,
    );
  }, [data]);

  const barChartData = useMemo(
    () => transformToBarChartData(cashFlowData, interval),
    [cashFlowData, interval],
  );

  const lineChartData = useMemo(
    () => transformToLineChartData(balanceData, cashFlowData),
    [balanceData, cashFlowData],
  );

  const segmentationResult = useMemo(
    () => segmentLineChartQuality(lineChartData),
    [lineChartData],
  );

  // Compute current balance from the latest balance point
  const legendData = useMemo<LegendData>(() => {
    // Get the latest balance from aggregatedBalanceValues
    const balanceEntries = Object.entries(balanceData);
    if (balanceEntries.length === 0) {
      return { currentBalance: null, currency, bankAccountCount };
    }

    // Sort by date descending to get the most recent balance
    const sortedEntries = balanceEntries.sort(([dateA], [dateB]) =>
      dateB.localeCompare(dateA),
    );
    const latestPoint = sortedEntries[0]?.[1];
    const latestBalance = latestPoint?.balance ?? null;
    const balanceQuality = latestPoint?.balanceQuality;

    return {
      currentBalance: latestBalance,
      currency,
      bankAccountCount,
      balanceQuality,
    };
  }, [balanceData, currency, bankAccountCount]);

  const contextValue = useMemo<CashflowChartContextType>(
    () => ({
      viewMode,
      setViewMode,
      interval,
      setInterval,
      legendData,
      barChartData,
      lineChartData: segmentationResult.chartData,
      lineChartSegmentKeys: {
        calculatedSegmentKeys: segmentationResult.calculatedSegmentKeys,
        importedSegmentKeys: segmentationResult.importedSegmentKeys,
        derivedSegmentKeys: segmentationResult.derivedSegmentKeys,
      },
    }),
    [
      viewMode,
      interval,
      setInterval,
      barChartData,
      segmentationResult,
      legendData,
    ],
  );

  return (
    <CashflowChartContext.Provider value={contextValue}>
      {children}
    </CashflowChartContext.Provider>
  );
}

export { useCashflowChartContext };

