import dayjs from "dayjs";
import { memo } from "react";

import { useTT } from "../../useTT.ts";
import { useIsColumnSelected } from "../SelectionContext.tsx";
import { useTimePeriodControls } from "../TimePeriodContext.tsx";
import { formatCashflowAmount } from "../utils/index.ts";
import type { CashflowTableCellProps } from "./types/index.ts";

/**
 * Reusable table cell component for the cashflow table.
 *
 * Performance: Memoized to prevent unnecessary re-renders. With 140+ cells
 * (7 periods x 20 categories), React.memo combined with useIsColumnSelected
 * ensures only cells whose highlight status changes re-render (typically ~14
 * cells during column highlighting: 7 cells losing highlight + 7 gaining it).
 */
function CashflowTableCellComponent({
  value,
  columnIndex,
  dateFrom,
  isBold = false,
  progressPercentage,
  colorMode,
  onClick,
}: CashflowTableCellProps) {
  const { language } = useTT();
  const isHighlighted = useIsColumnSelected(columnIndex);
  const { setPeriod } = useTimePeriodControls();

  const handleClick = onClick ?? (() => setPeriod(dayjs(dateFrom)));

  return (
    <TableCell
      onClick={handleClick}
      aria-selected={isHighlighted}
      sx={{
        textAlign: "right",
        cursor: "pointer",
        backgroundColor: "background.paper",
        borderBottom: isHighlighted ? "none" : undefined,
        borderRight: 1,
        borderRightColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        borderLeft: 1,
        borderLeftColor: isHighlighted
          ? "custom.borderSecondary"
          : "background.paper",
        fontWeight: isBold ? 600 : 400,
        color: getValueColor(colorMode, value),
        boxSizing: "border-box",
      }}
    >
      <Box>
        {formatCashflowAmount(value, language)}
        {progressPercentage !== undefined && (
          <LinearProgress
            variant="determinate"
            value={progressPercentage}
            sx={{
              mt: 0.5,
              height: 4,
              borderRadius: 1,
              backgroundColor: "action.hover",
              "& .MuiLinearProgress-bar": {
                backgroundColor:
                  progressPercentage > 100 ? "warning.main" : "primary.main",
              },
            }}
          />
        )}
      </Box>
    </TableCell>
  );
}

// Determine text color based on value
function getValueColor(
  colorMode: CashflowTableCellProps["colorMode"],
  value: number,
) {
  const mode = colorMode ?? "none";

  if (mode === "none") {
    return "text.primary";
  }

  if (mode === "final") {
    return value < 0 ? "error.main" : "text.primary";
  }

  // mode === "balance"
  if (value < 0) return "error.main";
  if (value > 0) return "success.main";
  return "text.primary";
}

export const CashflowTableCell = memo(CashflowTableCellComponent);
CashflowTableCell.displayName = "CashflowTableCell";

import { ReactNode, createContext, useContext, useMemo } from "react";

import type { Currency, Interval } from "../../types/cashflow.types.ts";
import type {
  CashFlowResponse,
  CashflowTableData,
  CategoryFilterState,
} from "../types/index.ts";
import { transformCashflowData } from "../utils/index.ts";

export type CashflowTableContextValue = {
  data: CashflowTableData | null;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
} & CategoryFilterState;

const CashflowTableContext = createContext<CashflowTableContextValue | null>(
  null,
);

export function useCashflowTable() {
  const context = useContext(CashflowTableContext);
  if (!context) {
    throw new Error(
      "useCashflowTable must be used within a CashflowTable provider",
    );
  }
  return context;
}

type CashflowTableProviderProps = {
  children: ReactNode;
  data: CashFlowResponse | undefined;
  interval: Interval;
  currency: Currency;
  bankAccountIdArray: string[];
  categoryFilterState: CategoryFilterState;
};

export function CashflowTableProvider({
  children,
  data,
  interval,
  currency,
  bankAccountIdArray,
  categoryFilterState,
}: CashflowTableProviderProps) {
  const tableData = useMemo(() => {
    if (!data) {
      return null;
    }
    return transformCashflowData(data);
  }, [data]);

  const context = useMemo(
    () => ({
      data: tableData,
      interval,
      currency,
      bankAccountIdArray,
      ...categoryFilterState,
    }),
    [tableData, interval, currency, bankAccountIdArray, categoryFilterState],
  );

  return (
    <CashflowTableContext.Provider value={context}>
      {children}
    </CashflowTableContext.Provider>
  );
}

import { Box, CircularProgress, Paper, Stack, Typography } from "@mui/material";
import { alpha } from "@mui/material/styles";

import { useTT } from "../useTT.ts";
import { CashflowFilterControls } from "./cashflowFilterControls/index.ts";
import { CHART_HEIGHT, CashflowCharts } from "./chart/index.ts";

type CurrentBalanceChartSectionProps = {
  isInitialLoading: boolean;
  isRefetching: boolean;
};

export function CurrentBalanceChartSection({
  isInitialLoading,
  isRefetching,
}: CurrentBalanceChartSectionProps) {
  const { tt } = useTT();

  return (
    <Paper sx={{ pt: 2 }}>
      <Stack
        sx={{
          justifyContent: "space-between",
          flexDirection: "row",
          alignItems: "center",
          px: 2,
        }}
      >
        <Typography variant="h4">{tt("currentAvailableBalance")}</Typography>
        <CashflowFilterControls />
      </Stack>

      {isInitialLoading ? (
        <Box
          sx={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            minHeight: CHART_HEIGHT,
            mt: 2,
          }}
        >
          <CircularProgress />
        </Box>
      ) : (
        <Box sx={{ position: "relative", mt: 2 }}>
          {isRefetching && (
            <Box
              sx={{
                position: "absolute",
                inset: 0,
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                zIndex: 1,
                bgcolor: (theme) => alpha(theme.palette.background.paper, 0.6),
                backdropFilter: "blur(2px)",
                WebkitBackdropFilter: "blur(2px)",
              }}
            >
              <CircularProgress />
            </Box>
          )}

          <CashflowCharts />
        </Box>
      )}
    </Paper>
  );
}

