import type { BwCashflowModel } from "@dfp/bw-sdk-bw-cashflow";
import { useContextBundle } from "@dfp/fnapp-context-bundle";
import { BadRequestError } from "@dfp/fnapp-error";

import { getAccountBalanceHistoryAndAggregatedValues } from "../shared/balanceHistory/accountBalanceHistory.ts";
import { getCashFlowHistory } from "../shared/cashFlow/cashFlowStates.ts";
import { filterAvailableAccounts } from "../shared/filterOwnBankAccounts.ts";
import {
  type CompanyFilterItem,
  getUsersAvailableAccounts,
} from "../shared/getUsersAvailableAccounts.ts";
import type { CashflowContextBundle } from "../types/CashflowContextBundle.type.ts";
import type {
  CurrencyType,
  TodayAggregatedBalance,
} from "../types/accountBalanceHistory.ts";
import type { RequestorIdentity } from "../types/requestorIdentity.type.ts";

interface RequestObject {
  requestorIdentity: RequestorIdentity;
  filtering: BwCashflowModel["getCashFlowAndBalanceStates"]["request"]["filtering"];
}

export async function getCashFlowAndBalanceStates(
  ctxBundle: CashflowContextBundle,
  _config: undefined,
  inputData: {
    requestData: RequestObject;
    response?: BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
  },
): Promise<{
  requestData: RequestObject;
  response?: BwCashflowModel["getCashFlowAndBalanceStates"]["response"];
}> {
  const { createCtxBundlePass, operationLog, operationTrace } =
    useContextBundle(ctxBundle, {
      op: getCashFlowAndBalanceStates.name,
    });
  operationLog.started();
  const ctxBundlePass = createCtxBundlePass();

  const filtering: BwCashflowModel["getCashFlowAndBalanceStates"]["request"]["filtering"] =
    inputData.requestData.filtering;

  const currency: CurrencyType = filtering.currency;
  const accounts: string[] = filtering.bankAccountIdArray;
  const dateFrom: string = filtering.dateFrom;
  const dateTo: string | undefined = filtering.dateTo;
  const returnBalanceStates: boolean = filtering.returnBalanceStates;
  const currentDate: string = new Date().toISOString().slice(0, 10); // YYYY-MM-DD

  // Get the list of accounts available to the user and filter the requested accounts against
  // that list to ensure the user has access to them.
  // This also serves as a validation step to prevent users from requesting data for accounts
  // they don't have access to.
  const usersAvailableAccounts: CompanyFilterItem[] =
    await getUsersAvailableAccounts(
      ctxBundlePass,
      inputData.requestData.requestorIdentity,
    );

  const filteredAccounts: string[] = filterAvailableAccounts(
    usersAvailableAccounts,
    accounts,
  );

  const returnEmpty =
    (): BwCashflowModel["getCashFlowAndBalanceStates"]["response"] => {
      return {
        accountBalanceHistoryArray: [],
        aggregatedBalanceValues: [],
        currency,
        todayAggregatedBalance: {
          balance: 0,
          balanceQuality: "CALCULATED",
        },
      };
    };

  if (filteredAccounts.length === 0) {
    inputData.response = returnEmpty();
    operationLog.finished();
    return inputData;
  }
  // Validate that the date range does not exceed the maximum allowed range of 913 days (30 months)
  validateDateRange(operationTrace, dateFrom, dateTo);

  ctxBundle.context.log.info(
    `${operationTrace} Loading Account balance history`,
  );
  const accountBalanceHistoryAndAggregatedValues =
    await getAccountBalanceHistoryAndAggregatedValues(
      ctxBundlePass,
      returnBalanceStates,
      filteredAccounts,
      currency,
      dateFrom,
      dateTo,
    );

  let todayAggregatedBalance: TodayAggregatedBalance;

  if (
    accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap[currentDate]
  ) {
    todayAggregatedBalance = {
      balance:
        accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap[
          currentDate
        ].balance,
      balanceQuality:
        accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap[
          currentDate
        ].balanceQuality,
    };
  } else {
    const today = await getAccountBalanceHistoryAndAggregatedValues(
      ctxBundlePass,
      returnBalanceStates,
      filteredAccounts,
      currency,
      currentDate,
      currentDate,
    );
    const todayEntry = today.aggregatedValuesMap[currentDate];

    const fallbackEntry = Object.values(
      accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap,
    ).at(-1);

    todayAggregatedBalance = todayEntry
      ? {
          balance: todayEntry.balance,
          balanceQuality: todayEntry.balanceQuality,
        }
      : {
          balance: fallbackEntry?.balance ?? 0,
          balanceQuality: fallbackEntry?.balanceQuality ?? "CALCULATED",
        };
  }

  ctxBundle.context.log.info(`${operationTrace} Loading CashFlow history`);
  const cashFlowStates = await getCashFlowHistory(
    ctxBundlePass,
    filtering,
    accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap,
  );

  inputData.response = {
    accountBalanceHistoryArray:
      accountBalanceHistoryAndAggregatedValues.balanceHistory,
    aggregatedBalanceValues: Object.values(
      accountBalanceHistoryAndAggregatedValues.aggregatedValuesMap,
    ),
    cashFlowStates: cashFlowStates,
    currency,
    todayAggregatedBalance,
  };
  operationLog.finished();
  return inputData;
}

/**
 * Validates that the date range between dateFrom and dateTo
 * does not exceed the maximum allowed range of 913 days (30 months).
 * @param operationTrace
 * @param dateFrom
 * @param dateTo
 */
const validateDateRange = (
  operationTrace: string,
  dateFrom: string,
  dateTo?: string,
): void => {
  const MAX_DAYS_RANGE = 913;
  const fromDate: Date = new Date(dateFrom);

  // If dateTo is not provided, use the current date
  const toDate: Date = dateTo ? new Date(dateTo) : new Date();

  if (Number.isNaN(fromDate.getTime()) || Number.isNaN(toDate.getTime())) {
    // this should never happen due to Joi validation,
    // but it's good to have this check in case of direct function calls
    throw new BadRequestError(
      operationTrace,
      "InvalidDateFormat",
      "Invalid date format",
      "The provided dateFrom or dateTo is not a valid date string.",
    );
  }

  const diffMs = toDate.getTime() - fromDate.getTime();
  if (diffMs < 0) {
    throw new BadRequestError(
      operationTrace,
      "InvalidDateRange",
      "Invalid date range",
      "dateTo must be the same as or after dateFrom.",
    );
  }
  const days: number = Math.floor(diffMs / (1000 * 60 * 60 * 24));

  if (days > MAX_DAYS_RANGE) {
    throw new BadRequestError(
      operationTrace,
      "DateRangeTooLarge",
      "The date range must not exceed 913 days",
      "The provided date range exceeds the maximum allowed range of 913 days (30 months).",
    );
  }
};

