    const perAccountFilled = fillMissingDates(accountDailyMap, dateTo);

    for (const [date, balance] of Object.entries(perAccountFilled)) {
      if (!dailyMap[date]) {
        dailyMap[date] = {
          balance: 0,
          date,
          balanceQuality: balance.balanceQuality,
          accounts: includeCompanyAccountsBalance ? [] : undefined,
        };
      }

      dailyMap[date].balance = addRounded(
        dailyMap[date].balance,
        balance.balance,
      );

      // CALCULATED > DERIVED > IMPORTED
      if (balance.balanceQuality === "CALCULATED") {
        dailyMap[date].balanceQuality = "CALCULATED";
      } else if (balance.balanceQuality === "DERIVED") {
        if (dailyMap[date].balanceQuality !== "CALCULATED") {
          dailyMap[date].balanceQuality = "DERIVED";
        }
      }

      if (includeCompanyAccountsBalance) {
        dailyMap[date].accounts.push({
          balance: balance.balance ?? 0,
          balanceQuality: balance.balanceQuality,
          accountId: account.bankAccountRef.documentId,

          originalCurrency: balance?.originalCurrency,
          originalCurrencyBalance: balance?.originalCurrencyBalance,
        });
      }
    }
  }
  operationLog.finished();
  return dailyMap;
};

export const aggregateDailyBalancesForAccount = (
  ctxBundle: ContextBundle,
  balanceStateArray: DmbBankaccountsModel["getBalanceHistory"]["response"]["accountBalanceHistoryArray"][0]["balanceStateArray"],
  currencyToCalculate: CurrencyType,
  includeCompanyAccountsBalance: boolean,
): Record<string, Balance> => {
  const { operationLog, operationTrace } = useContextBundle(ctxBundle, {
    op: aggregateDailyBalancesForAccount.name,
  });
  operationLog.started();

  const dailyMap: Record<string, Balance> = {};
  for (const state of balanceStateArray) {
    if (!state.balances || !state.balances.amounts) {
      ctxBundle.context.log.warn(
        `${operationTrace} Missing balances in balance state for ${state.timestamp}`,
      );
      continue;
    }
    const date: string = state.timestamp.split("T")[0];

    if (!dailyMap[date]) {
      dailyMap[date] = {
        balance: 0,
        date,
        balanceQuality: state.balances.balanceQuality,

        // resolving original currency balance at account level,
        originalCurrency: includeCompanyAccountsBalance
          ? state.balances?.originalAmount?.currency
          : undefined,
        originalCurrencyBalance:
          includeCompanyAccountsBalance &&
          state.balances?.originalAmount?.currency
            ? 0
            : undefined,

