  ```typescript
  import type { LineChartDataPoint } from "../../types/cashflow.types.ts";

  /**
   * Extends a quality run with a synthetic point from the previous real day when
   * possible. That extra anchor lets the chart draw a continuous stroke through
   * a quality transition without visually reconnecting unrelated later runs.
   */
  function assignRunSegment(
    raw: LineChartDataPoint[],
    segmented: LineChartDataPoint[],
    start: number,
    end: number,
    seriesKey: string,
  ): void {
    if (start > 0) {
      segmented[start - 1] = {
        ...segmented[start - 1],
        [seriesKey]: raw[start - 1].balance,
      };
    }

    for (let index = start; index <= end; index += 1) {
      segmented[index] = {
        ...segmented[index],
        [seriesKey]: raw[index].balance,
      };
    }
  }

  /**
   * Splits the line chart data into contiguous quality runs and assigns each
   * run a unique series key so the chart library renders distinct visual styles
   * per quality. Adjacent runs share a bridge point so the overall line remains
   * visually continuous across quality transitions.
   */
  export function segmentLineChartQuality(data: LineChartDataPoint[]): {
    chartData: LineChartDataPoint[];
    calculatedSegmentKeys: string[];
    importedSegmentKeys: string[];
    derivedSegmentKeys: string[];
  } {
    if (data.length === 0) {
      return {
        chartData: [],
        calculatedSegmentKeys: [],
        importedSegmentKeys: [],
        derivedSegmentKeys: [],
      };
    }

    const segmented = data.map((entry) => ({ ...entry }));
    const calculatedSegmentKeys: string[] = [];
    const importedSegmentKeys: string[] = [];
    const derivedSegmentKeys: string[] = [];
    let seriesIndex = 0;
    let runStart = 0;

    for (let index = 1; index <= data.length; index += 1) {
      const current = data[index];
      const previous = data[index - 1];
      const runContinues = current?.balanceQuality === previous?.balanceQuality;

      if (runContinues) {
        continue;
      }

      const runEntry = data[runStart];
      if (runEntry !== undefined && runStart <= index - 1) {
        const { balanceQuality } = runEntry;
        let seriesKey: string;

        if (balanceQuality === "CALCULATED") {
          seriesKey = `calculatedSegment${seriesIndex}`;
          calculatedSegmentKeys.push(seriesKey);
        } else if (balanceQuality === "IMPORTED") {
          seriesKey = `importedSegment${seriesIndex}`;
          importedSegmentKeys.push(seriesKey);
        } else {
          seriesKey = `derivedSegment${seriesIndex}`;
          derivedSegmentKeys.push(seriesKey);
        }

        seriesIndex += 1;
        assignRunSegment(data, segmented, runStart, index - 1, seriesKey);
      }

      runStart = index;
    }

    return {
      chartData: segmented,
      calculatedSegmentKeys,
      importedSegmentKeys,
      derivedSegmentKeys,
    };
  }
  ```

