type BalanceChartSummaryProps = {
  filters: Omit<
    BalanaceChartFilters,
    "dateTo" | "range" | "returnCompanyBalance" | "returnCompanyAccountsBalance"
  >;
};

export function BalanceChartSummary({ filters }: BalanceChartSummaryProps) {
  const { tt } = useTT();

  const { data, isPending, isFetching } = useGetHistoricalBalance({
    params: {
      ...filters,
      returnCompanyBalance: filters.returnOriginalCurrencyCostsAndIncomes,
      returnCompanyAccountsBalance:
        filters.returnOriginalCurrencyCostsAndIncomes,
      range: 7,
      dateTo: dayjs().format("YYYY-MM-DD"),
    },
    select: (data) => ({
      balance: data.finalBalance,
      quality: data.balanceQuality,
      currency: data.originalCurrency ?? data.currency,
      income: data.income,
      costs: data.costs,
    }),
  });

  const showSkeleton = isPending || isFetching;

  return (
    <Stack
      sx={{
        flexDirection: "row",
        alignItems: "center",
        justifyContent: "space-between",
        gap: 2,
      }}
    >
      {showSkeleton ? (
        <Skeleton variant="rounded" width={200} height={34} />
      ) : (
        <Stack sx={{ flexDirection: "row", alignItems: "center", gap: 1 }}>
          {data?.quality === "DERIVED" && (
            <Tooltip title={tt("totalBalance.inaccurateTooltip")}>
              <Chip
                sx={{
                  width: 30,
                  height: 30,
                }}
                variant="outlined"
                color="warning"
                icon={<IconAlertTriangle width={20} height={20} />}
              />
            </Tooltip>
          )}
          <Typography variant="h1">
            <AnimatedCurrencyAmount
              currency={data?.currency ?? DEFAULT_CURRENCY_FALLBACK}
              value={data?.balance ?? 0}
            />
          </Typography>
        </Stack>
      )}
      {showSkeleton ? (
        <Skeleton variant="rounded" width={160} height={34} />
      ) : (
        <MoneyInMoneyOut
          income={data?.income ?? 0}
          costs={data?.costs ?? 0}
          currency={data?.currency ?? DEFAULT_CURRENCY_FALLBACK}
        />
      )}
    </Stack>
  );
}

