import { formatCurrencyAmountCompact } from "@dfp/isomorphic-currency-amount";

/**
 * Formats a numeric amount as a compact, locale-aware currency string,
 * e.g. "€1.2M", "-€500K", or "CZK 1K".
 *
 * @param currency      ISO 4217 currency code (e.g. "EUR", "CZK")
 * @param language      BCP 47 language tag (e.g. "en", "cs")
 * @param value         The numeric value to format
 * @param forceNegative When true, the value is negated before formatting unless it is 0.
 *                      Use this when the value is semantically negative (e.g. costs) but
 *                      stored as a positive number in the API response.
 */
export function formatCurrencyShortAmount(
  currency: string,
  language: string,
  value: number,
  forceNegative = false,
): string {
  const actualValue = forceNegative && value !== 0 ? -value : value;
  return formatCurrencyAmountCompact({
    value: actualValue,
    currency,
    language,
  });
}
